func TestCalculateDiscount(t *testing.T) {
    tests := []struct {
        name     string
        price    float64
        role     string
        wantDisc float64
    }{
        {name: "premium_20pct", price: 100, role: "premium", wantDisc: 20},
        {name: "standard_no_disc", price: 100, role: "user", wantDisc: 0},
        {name: "zero_price", price: 0, role: "premium", wantDisc: 0},
    }

    for _, tc := range tests {
        t.Run(tc.name, func(t *testing.T) {
            got := CalculateDiscount(tc.price, tc.role)
            if got != tc.wantDisc {
                t.Errorf("CalculateDiscount(%v, %q) = %v, want %v",
                    tc.price, tc.role, got, tc.wantDisc)
            }
        })
    }
}

for _, tc := range tests {
    tc := tc // capture loop variable — required in Go < 1.22
    t.Run(tc.name, func(t *testing.T) {
        t.Parallel()
        // ... test body using tc
    })
}

import (
    "github.com/stretchr/testify/assert"
    "github.com/stretchr/testify/require"
)

func TestGetUser(t *testing.T) {
    user, err := GetUser(ctx, 1)
    require.NoError(t, err)          // stop if error
    require.NotNil(t, user)          // stop if nil (prevents nil deref below)
    assert.Equal(t, "alice", user.Name)
    assert.Equal(t, "admin", user.Role)
}

func assertUserEqual(t *testing.T, want, got *User) {
    t.Helper()
    if want.ID != got.ID || want.Name != got.Name {
        t.Errorf("user mismatch: want %+v, got %+v", want, got)
    }
}

// In the service package (consumer side)
type UserStore interface {
    FindByID(ctx context.Context, id int) (*User, error)
    Save(ctx context.Context, user *User) error
}

// Manual mock for tests
type stubUserStore struct {
    user *User
    err  error
}

func (s *stubUserStore) FindByID(_ context.Context, _ int) (*User, error) {
    return s.user, s.err
}

func (s *stubUserStore) Save(_ context.Context, _ *User) error {
    return s.err
}

func TestGetUserHandler(t *testing.T) { store := &stubUserStore{user: &User{ID: 1, Name: "Alice"}} handler := NewUserHandler(store)
req := httptest.NewRequest(http.MethodGet, "/users/1", nil) rec := httptest.NewRecorder()
handler.ServeHTTP(rec, req)
require.Equal(t, http.StatusOK, rec.Code) var got User require.NoError(t, json.NewDecoder(rec.Body).Decode(&got)) assert.Equal(t, "Alice", got.Name) }

func TestAPIClient_GetUser(t *testing.T) {
    srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        w.Header().Set("Content-Type", "application/json")
        json.NewEncoder(w).Encode(User{ID: 1, Name: "Alice"})
    }))
    defer srv.Close()

    client := NewAPIClient(srv.URL)
    user, err := client.GetUser(context.Background(), 1)

    require.NoError(t, err)
    assert.Equal(t, "Alice", user.Name)
}

func BenchmarkParseJSON(b *testing.B) {
    data := []byte(`{"id":1,"name":"Alice","role":"admin"}`)
    b.ResetTimer()

    for i := 0; i < b.N; i++ {
        var u User
        _ = json.Unmarshal(data, &u)
    }
}

// Go 1.24+
func BenchmarkParseJSON(b *testing.B) {
    data := []byte(`{"id":1,"name":"Alice"}`)
    var u User
    for b.Loop() {
        _ = json.Unmarshal(data, &u)
    }
}

func FuzzParseUserID(f *testing.F) {
    f.Add("42")
    f.Add("")
    f.Add("abc")
    f.Fuzz(func(t *testing.T, input string) {
        // Must not panic — even on adversarial input
        _, _ = ParseUserID(input)
    })
}

